def boyer_moore_majority_element(nums):
    if not nums:
        return None

    candidate = None
    count = 0

    for num in nums:
        if count == 0:
            candidate = num
            count = 1
        elif num == candidate:
            count += 1
        else:
            count -= 1

    majority_count = 0
    for num in nums:
        if num == candidate:
            majority_count += 1

    if majority_count > len(nums) // 2:
        return candidate
    else:
        return None
